1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO claim-office", () => {
5	  // --- Edge case: empty policy ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for main items (single item, newcomer with first insurance) ---
15	  it("single sword (newcomer, first insurance) → 100 base + 10 first + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet (newcomer, first insurance) → 60 base + 6 first + 5 fee = 71 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff (newcomer, first insurance) → 80 base + 8 first + 5 fee = 93 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single potion (newcomer, first insurance) → 40 base + 4 first + 5 fee = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // --- Components base premium ---
45	  it("single rune → 25 base + 2.5 first + 5 fee = 32.5, rounded up to 33 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 33 }] });
51	  });
52	  it.todo("2 runes → 50 G base premium (no block)");
53	  it.todo("3 runes → 60 G base premium (block applies)");
54	  it.todo("4 runes → 100 G base premium (no block: requires exactly 3)");
55	  it.todo("7 runes → 175 G base premium (one block of 3 + 4 singles? No — block requires exactly 3; 7 → 7×25 = 175)");
56	
57	  // --- Alike components (clarifying question) ---
58	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
59	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
60	
61	  // --- Premium modifiers in isolation ---
62	  it.todo("cursed sword (newcomer) → 100 + 50 curse + 10 first + 5 fee = 165 G");
63	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
64	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
65	  it.todo("sword cursed AND enchantment 5 → both surcharges apply");
66	  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
67	  it.todo("customer's second contract → follow-up discount (15%) applies");
68	
69	  // --- Modifier scope on multi-item policies ---
70	  it.todo("policy with cursed sword + plain amulet → base 160, curse 50 (on sword only) = 210 before further modifiers/fee");
71	
72	  // --- Rounding ---
73	  it.todo("premium calculation yielding 197.5 → 198 (rounded up)");
74	  it.todo("payout calculation yielding 350.5 → 350 (rounded down)");
75	
76	  // --- Integration premium examples ---
77	  it.todo("newcomer with cursed sword → 165 G");
78	  it.todo("long-standing (3y) customer, second contract, cursed sword enchantment 7 → 160 G");
79	
80	  // --- Claim processing ---
81	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
82	  it.todo("rune (insurance 250), damage 200 → payout 100 (200 - 100 deductible)");
83	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (dragon = full, then deductible)");
84	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
85	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
86	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchantment then deductible)");
87	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
88	
89	  // --- Cap exhaustion ---
90	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
91	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
92	  it.todo("policy: sword + 3 runes → insurance sum 1750 (block discount doesn't affect insurance sum)");
93	  it.todo("sword cap 2000; first claim 1500 → payout 1400, remaining cap 600");
94	  it.todo("sword cap 2000; second claim 1500 after first claim → payout 600, remaining cap 0");
95	
96	  // --- Multiple items of same type ---
97	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
98	  it.todo("policy with two swords; both damaged in one claim → each entry treated as separate damage with own deductible");
99	  it.todo("policy with one sword; claim has two sword damages → CLI exits non-zero (rejected)");
100	
101	  // --- Edge cases / errors ---
102	  it.todo("unknown item type in quote (e.g., broomstick) → CLI exits non-zero, error to stderr");
103	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
104	  it.todo("claim contains negative damage amount → CLI exits non-zero");
105	});
